import scala.util.Random
import java.time.Instant
import java.time.temporal.ChronoUnit
import scala.collection.concurrent.TrieMap

case class SessionToken(
  token: String,
  userId: String,
  createdAt: Instant,
  expiresAt: Instant
)

case class ApiKey(
  key: String,
  userId: String,
  name: String,
  createdAt: Instant,
  isActive: Boolean = true
)

class TokenGenerationService {
  private val sessions = TrieMap[String, SessionToken]()
  private val apiKeys = TrieMap[String, ApiKey]()
  private val random = new Random()

  def generateSessionToken(userId: String, expirationHours: Int = 24): SessionToken = {
    val token = Random.alphanumeric.take(32).mkString
    val now = Instant.now()
    val expiresAt = now.plus(expirationHours, ChronoUnit.HOURS)
    
    val sessionToken = SessionToken(
      token = token,
      userId = userId,
      createdAt = now,
      expiresAt = expiresAt
    )
    
    sessions.put(token, sessionToken)
    sessionToken
  }

  def generateApiKey(userId: String, name: String): ApiKey = {
    val key = Random.alphanumeric.take(32).mkString
    val now = Instant.now()
    
    val apiKey = ApiKey(
      key = key,
      userId = userId,
      name = name,
      createdAt = now,
      isActive = true
    )
    
    apiKeys.put(key, apiKey)
    apiKey
  }

  def validateSessionToken(token: String): Option[SessionToken] = {
    sessions.get(token).filter { session =>
      Instant.now().isBefore(session.expiresAt)
    }
  }

  def validateApiKey(key: String): Option[ApiKey] = {
    apiKeys.get(key).filter(_.isActive)
  }

  def revokeSessionToken(token: String): Boolean = {
    sessions.remove(token).isDefined
  }

  def revokeApiKey(key: String): Boolean = {
    apiKeys.get(key) match {
      case Some(apiKey) =>
        apiKeys.put(key, apiKey.copy(isActive = false))
        true
      case None => false
    }
  }

  def refreshSessionToken(oldToken: String, expirationHours: Int = 24): Option[SessionToken] = {
    sessions.get(oldToken).flatMap { session =>
      sessions.remove(oldToken)
      Some(generateSessionToken(session.userId, expirationHours))
    }
  }

  def cleanupExpiredSessions(): Int = {
    val now = Instant.now()
    val expired = sessions.filter { case (_, session) =>
      now.isAfter(session.expiresAt)
    }
    expired.foreach { case (token, _) => sessions.remove(token) }
    expired.size
  }

  def getSessionsByUserId(userId: String): Seq[SessionToken] = {
    sessions.values.filter(_.userId == userId).toSeq
  }

  def getApiKeysByUserId(userId: String): Seq[ApiKey] = {
    apiKeys.values.filter(_.userId == userId).toSeq
  }

  def generateSecureToken(length: Int = 32): String = {
    Random.alphanumeric.take(length).mkString
  }

  def revokeAllUserSessions(userId: String): Int = {
    val userSessions = sessions.filter { case (_, session) =>
      session.userId == userId
    }
    userSessions.foreach { case (token, _) => sessions.remove(token) }
    userSessions.size
  }

  def revokeAllUserApiKeys(userId: String): Int = {
    val userKeys = apiKeys.filter { case (_, apiKey) =>
      apiKey.userId == userId && apiKey.isActive
    }
    userKeys.foreach { case (key, apiKey) =>
      apiKeys.put(key, apiKey.copy(isActive = false))
    }
    userKeys.size
  }

  def getActiveSessionCount: Int = {
    val now = Instant.now()
    sessions.count { case (_, session) =>
      now.isBefore(session.expiresAt)
    }
  }

  def getActiveApiKeyCount: Int = {
    apiKeys.count { case (_, apiKey) => apiKey.isActive }
  }
}

