class TokenAuthenticationMiddleware(tokenService: TokenGenerationService) {
  def authenticateWithSessionToken(token: String): Option[String] = {
    tokenService.validateSessionToken(token).map(_.userId)
  }

  def authenticateWithApiKey(key: String): Option[String] = {
    tokenService.validateApiKey(key).map(_.userId)
  }

  def authenticate(credentials: Either[String, String]): Option[String] = {
    credentials match {
      case Left(sessionToken) => authenticateWithSessionToken(sessionToken)
      case Right(apiKey) => authenticateWithApiKey(apiKey)
    }
  }
}

